"""
Bidirectional sync between local JSON files and Grafana dashboards.

On startup: pushes JSON files into Grafana via API (regular, editable dashboards).
Each poll: detects which side changed and syncs in that direction.
  - File edited on disk  → pushed to Grafana
  - Dashboard saved in UI → written back to file

To add a new dashboard, add its UID → filename mapping to DASHBOARDS below.
"""
import json
import os
import time
import urllib.request
import urllib.error

GRAFANA_URL = os.environ.get("GRAFANA_URL", "http://grafana:3000")
DASHBOARDS_DIR = os.environ.get("DASHBOARDS_DIR", "/dashboards")
INTERVAL = int(os.environ.get("INTERVAL", "10"))

DASHBOARDS = {
    "claude-code-monitor": "grafana-dashboard.json",
    "claude-cost": "grafana-dashboard-cost.json",
    "claude-events": "grafana-dashboard-events.json",
    "claude-skills": "grafana-dashboard-skills.json",
    "claude-session": "grafana-dashboard-session.json",
    "claude-unified": "grafana-dashboard-unified.json",
}


def normalize(dashboard):
    d = {k: v for k, v in dashboard.items() if k not in ("id", "version")}
    return json.dumps(d, indent=2, sort_keys=True)


def api_get(path):
    with urllib.request.urlopen(f"{GRAFANA_URL}{path}", timeout=10) as resp:
        return json.load(resp)


def api_post(path, body):
    data = json.dumps(body).encode()
    req = urllib.request.Request(
        f"{GRAFANA_URL}{path}",
        data=data,
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    with urllib.request.urlopen(req, timeout=10) as resp:
        return json.load(resp)


def fetch_dashboard(uid):
    try:
        return api_get(f"/api/dashboards/uid/{uid}")["dashboard"]
    except urllib.error.HTTPError as e:
        if e.code == 404:
            return None
        raise


def push_dashboard(dashboard):
    api_post("/api/dashboards/db", {
        "dashboard": dashboard,
        "overwrite": True,
        "folderId": 0,
    })


def read_file(outfile):
    try:
        return json.loads(open(outfile).read())
    except Exception:
        return None


def write_file(outfile, dashboard):
    with open(outfile, "w") as f:
        f.write(normalize(dashboard) + "\n")


def wait_for_grafana():
    print(f"Waiting for Grafana at {GRAFANA_URL}...", flush=True)
    while True:
        try:
            api_get("/api/health")
            break
        except Exception:
            time.sleep(2)
    print("Grafana ready.", flush=True)


class DashboardSyncer:
    def __init__(self, uid, filename):
        self.uid = uid
        self.outfile = os.path.join(DASHBOARDS_DIR, filename)
        self.last_known = None

    def bootstrap(self):
        file_dash = read_file(self.outfile)
        if file_dash is None:
            print(f"Warning: could not read {self.outfile}", flush=True)
            return

        file_norm = normalize(file_dash)
        remote = fetch_dashboard(self.uid)

        if remote is None or normalize(remote) != file_norm:
            file_dash["uid"] = self.uid
            push_dashboard(file_dash)
            print(f"Imported: {self.outfile} → Grafana ({self.uid})", flush=True)
        else:
            print(f"Up to date: {self.uid}", flush=True)

        self.last_known = file_norm

    def poll(self):
        file_dash = read_file(self.outfile)
        remote = fetch_dashboard(self.uid)
        if file_dash is None or remote is None:
            return

        file_norm = normalize(file_dash)
        remote_norm = normalize(remote)
        file_changed = file_norm != self.last_known
        grafana_changed = remote_norm != self.last_known

        if file_changed and not grafana_changed:
            file_dash["uid"] = self.uid
            push_dashboard(file_dash)
            self.last_known = file_norm
            print(f"File → Grafana: {self.uid}", flush=True)
        elif grafana_changed and not file_changed:
            write_file(self.outfile, remote)
            self.last_known = remote_norm
            print(f"Grafana → file: {self.uid}", flush=True)
        elif file_changed and grafana_changed:
            file_dash["uid"] = self.uid
            push_dashboard(file_dash)
            self.last_known = file_norm
            print(f"Conflict (file wins): {self.uid}", flush=True)


if __name__ == "__main__":
    wait_for_grafana()
    script_mtime = os.path.getmtime(__file__)
    syncers = [DashboardSyncer(uid, fn) for uid, fn in DASHBOARDS.items()]
    for s in syncers:
        s.bootstrap()
    print(f"Polling every {INTERVAL}s...", flush=True)
    while True:
        time.sleep(INTERVAL)
        if os.path.getmtime(__file__) != script_mtime:
            print("Script changed, exiting for restart...", flush=True)
            raise SystemExit(0)
        for s in syncers:
            s.poll()
